        focusedTextColor = TextPrimary,
        unfocusedTextColor = TextPrimary,
        focusedLabelColor = TextPrimary,
        unfocusedLabelColor = TextSecondary,
        focusedPlaceholderColor = TextSecondary,
        unfocusedPlaceholderColor = TextSecondary,
        cursorColor = PrimaryAccent,
        focusedBorderColor = PrimaryAccent,
        unfocusedBorderColor = DividerBorder
    )

    if (successState != null) {
        RequestCreatedDialog(
            service = successState.service,
            areaName = requestAreaOptions.firstOrNull { it.id == successState.service.areaId }?.label
                ?: "Area ${successState.service.areaId}",
            onDismiss = { viewModel.resetState() },
            onConfirm = {
                viewModel.resetState()
                onViewDetails()
            }
        )
    }

    Scaffold(
        containerColor = Background,
        topBar = {
            TopAppBar(
                title = {
                    Text(
                        text = "Create service request",
                        color = TextPrimary,
                        fontWeight = FontWeight.Bold
                    )
                },
                navigationIcon = {
                    IconButton(onClick = onBack) {
                        Icon(
                            imageVector = Icons.AutoMirrored.Filled.ArrowBack,
                            contentDescription = "Back",
                            tint = TextPrimary
                        )
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(containerColor = Background)
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .verticalScroll(rememberScrollState())
                .padding(horizontal = 16.dp, vertical = 12.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            Card(
                modifier = Modifier.fillMaxWidth(),
                shape = RoundedCornerShape(16.dp),
                colors = CardDefaults.cardColors(containerColor = CardBackground)
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(16.dp),
                    verticalArrangement = Arrangement.spacedBy(14.dp)
                ) {
                    Text(
                        text = "Tell us what service you need",
                        style = MaterialTheme.typography.titleMedium,
                        color = TextPrimary,
                        fontWeight = FontWeight.SemiBold
                    )
                    Text(
                        text = "Create a tour request and available partners in the selected area will be able to accept it.",
                        style = MaterialTheme.typography.bodyMedium,
                        color = TextSecondary
                    )

                    ExposedDropdownMenuBox(
                        expanded = areaExpanded,
                        onExpandedChange = { areaExpanded = !areaExpanded }
                    ) {
                        OutlinedTextField(
                            value = selectedArea?.label.orEmpty(),
                            onValueChange = {},
                            readOnly = true,
                            label = { Text("Destination area") },
                            placeholder = { Text("Select a city") },
                            trailingIcon = {
                                ExposedDropdownMenuDefaults.TrailingIcon(expanded = areaExpanded)
                            },
                            modifier = Modifier
                                .menuAnchor()
                                .fillMaxWidth(),
                            shape = RoundedCornerShape(12.dp),
                            colors = requestFieldColors
                        )
                        DropdownMenu(
                            expanded = areaExpanded,
                            onDismissRequest = { areaExpanded = false }
                        ) {
                            requestAreaOptions.forEach { option ->
                                DropdownMenuItem(
                                    text = { Text(option.label) },
                                    onClick = {
                                        selectedArea = option
                                        areaExpanded = false
                                    }
                                )
                            }
                        }
                    }

                    OutlinedTextField(
                        value = agreedHoursText,
                        onValueChange = { value ->
                            agreedHoursText = value.filter { it.isDigit() }.take(2)
                        },
                        label = { Text("Agreed hours") },
                        placeholder = { Text("Example: 2") },
                        keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number),
                        modifier = Modifier.fillMaxWidth(),
                        shape = RoundedCornerShape(12.dp),
                        colors = requestFieldColors
                    )

                    OutlinedTextField(
                        value = hourlyRateText,
                        onValueChange = { value ->
                            hourlyRateText = value.filter { it.isDigit() || it == '.' }.let { filtered ->
                                val parts = filtered.split('.')
                                if (parts.size <= 2) filtered else parts[0] + "." + parts[1]
                            }
                        },
                        label = { Text("Hourly rate (COP)") },
                        placeholder = { Text("Example: 45000") },
                        keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                        modifier = Modifier.fillMaxWidth(),
                        shape = RoundedCornerShape(12.dp),
                        colors = requestFieldColors
                    )

                    OutlinedTextField(
                        value = meetingPointText,
                        onValueChange = { meetingPointText = it.take(255) },
                        label = { Text("Meeting point / notes") },
                        placeholder = { Text("Optional: Historic center, plaza, museum entrance...") },
                        modifier = Modifier.fillMaxWidth(),
                        minLines = 3,
                        shape = RoundedCornerShape(12.dp),
                        colors = requestFieldColors
                    )
                }
            }

            if (errorState != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(containerColor = Color(0xFFFFEBEE)),
                    shape = RoundedCornerShape(14.dp)
                ) {
                    Text(
                        text = errorState.message,
                        color = Color(0xFFC62828),
                        modifier = Modifier.padding(14.dp)
                    )
                }
            }

            RequestSummaryCard(
                areaName = selectedArea?.label ?: "Not selected",
                agreedHours = agreedHoursText.ifBlank { "-" },
                hourlyRate = hourlyRateText.ifBlank { "-" },
                meetingPoint = meetingPointText.ifBlank { "No additional notes" }
            )

            Button(
                onClick = {
                    viewModel.requestTour(
                        areaId = selectedArea!!.id,
                        agreedHours = agreedHours!!,
                        hourlyRate = hourlyRate!!,
                        locationDescription = meetingPointText
                    )
                },
                enabled = canSubmit,
                modifier = Modifier.fillMaxWidth(),
                colors = ButtonDefaults.buttonColors(containerColor = PrimaryAccent),
                shape = RoundedCornerShape(28.dp),
                contentPadding = PaddingValues(vertical = 14.dp)
            ) {
                if (isLoading) {
                    CircularProgressIndicator(
                        modifier = Modifier.height(20.dp),
                        color = Color.White,
                        strokeWidth = 2.dp
                    )
                } else {
                    Text(
                        text = "Create service",
                        fontSize = 16.sp,
                        fontWeight = FontWeight.Bold,
                        color = TextPrimary
                    )
                }
            }
        }
    }
}

@Composable
private fun RequestSummaryCard(
    areaName: String,
    agreedHours: String,
    hourlyRate: String,
    meetingPoint: String
) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        shape = RoundedCornerShape(16.dp),
        colors = CardDefaults.cardColors(containerColor = CardBackground)
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(10.dp)
        ) {
            Text(
                text = "Request summary",
                style = MaterialTheme.typography.titleMedium,
                fontWeight = FontWeight.SemiBold,
                color = TextPrimary
            )
            SummaryRow(label = "Area", value = areaName)
            SummaryRow(label = "Hours", value = agreedHours)
            SummaryRow(label = "Hourly rate", value = if (hourlyRate == "-") hourlyRate else "$hourlyRate COP")
            SummaryRow(label = "Notes", value = meetingPoint)
        }
    }
}

@Composable
private fun SummaryRow(label: String, value: String) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween
    ) {
        Text(text = label, color = TextSecondary)
        Spacer(modifier = Modifier.weight(1f))
        Text(
            text = value,
            color = TextPrimary,
            fontWeight = FontWeight.Medium,
            modifier = Modifier.padding(start = 12.dp)
        )
    }
}

@Composable
private fun RequestCreatedDialog(
    service: ServiceResponse,
    areaName: String,
    onDismiss: () -> Unit,
    onConfirm: () -> Unit
) {
    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Service created successfully") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                Text("Your request is now visible to available partners.")
                Text("Service ID: ${service.serviceId}")
                Text("Area: $areaName")
                Text("Status: ${service.status}")
                Text("Hours: ${service.agreedHours}")
                Text("Hourly rate: ${service.hourlyRate} COP")
            }
        },
        confirmButton = {
            TextButton(onClick = onConfirm) {
                Text("Done")
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) {
                Text("Stay here")
            }
        }
    )
}

package com.sismptm.client.ui.screens

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.sismptm.client.data.remote.CreateServiceRequest
import com.sismptm.client.data.remote.RetrofitClient
import com.sismptm.client.data.remote.ServiceResponse
import com.sismptm.client.utils.SessionManager
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import org.json.JSONObject

/** Maps city names to their backend area IDs. */
val CITY_AREA_MAP: Map<String, Long> = mapOf(
    "Popayán"  to 1L,
    "Cali"     to 2L,
    "Medellín" to 3L,
    "Bogotá"   to 4L
)

/** Returns the area ID for the given city name (case-insensitive, accent-insensitive). */
fun cityNameToAreaId(cityName: String): Long? {
    val normalized = cityName.trim().lowercase()
    return CITY_AREA_MAP.entries.firstOrNull {
        it.key.lowercase() == normalized ||
        it.key.lowercase().contains(normalized) ||
        normalized.contains(it.key.lowercase())
    }?.value
}

class RequestTourViewModel : ViewModel() {

    sealed interface RequestUiState {
        object Idle : RequestUiState
        object Loading : RequestUiState
        data class Success(val service: ServiceResponse) : RequestUiState
        data class Error(val message: String) : RequestUiState
    }

    private val _uiState = MutableStateFlow<RequestUiState>(RequestUiState.Idle)
    val uiState: StateFlow<RequestUiState> = _uiState.asStateFlow()

    fun requestTour(
        areaId: Long,
        agreedHours: Int,
        hourlyRate: Double,
        locationDescription: String?
    ) {
        val clientId = SessionManager.clientId
        if (clientId == 0L) {
            _uiState.value = RequestUiState.Error("Session expired. Please log in again.")
            return
        }

        // Backend endpoint requires hasRole('CLIENT')
        if (!SessionManager.userRole.equals("CLIENT", ignoreCase = true)) {
            _uiState.value = RequestUiState.Error(
                "Your account role is '${SessionManager.userRole}'. Only CLIENT can request tours."
            )
            return
        }

        viewModelScope.launch {
            _uiState.value = RequestUiState.Loading
            try {
                val request = CreateServiceRequest(
                    areaId = areaId,
                    startLocationDescription = locationDescription?.ifBlank { null },
                    agreedHours = agreedHours,
                    hourlyRate = hourlyRate
                )
                val response = RetrofitClient.apiService.createService(request)
                if (response.isSuccessful) {
                    val service = response.body()
                    if (service != null) {
                        _uiState.value = RequestUiState.Success(service)
                    } else {
                        _uiState.value = RequestUiState.Error("Server returned an empty response.")
                    }
                } else {
                    val errorBody = response.errorBody()?.string().orEmpty()
                    _uiState.value = RequestUiState.Error(
                        when (response.code()) {
                            403 -> "Forbidden (403). Token is valid, but backend denied CLIENT role access."
                            401 -> "Unauthorized (401). Please log in again."
                            409 -> parseBackendError(errorBody).ifBlank {
                                "You already have an active service request."
                            }
                            else -> parseBackendError(errorBody).ifBlank {
                                "Error ${response.code()}: $errorBody"
                            }
                        }
                    )
                }
            } catch (e: Exception) {
                _uiState.value = RequestUiState.Error(
                    e.localizedMessage ?: "Connection error"
                )
            }
        }
    }

    fun resetState() {
        _uiState.value = RequestUiState.Idle
    }

    private fun parseBackendError(body: String): String = runCatching {
        if (body.isBlank()) "" else JSONObject(body).optString("error", "")
    }.getOrDefault("")
}

package com.sismptm.client.ui.screens

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.sismptm.client.data.remote.CreateServiceRequest
import com.sismptm.client.data.remote.RetrofitClient
import com.sismptm.client.data.remote.ServiceResponse
import com.sismptm.client.utils.SessionManager
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import org.json.JSONObject
import java.text.Normalizer

/** Maps city names to their backend area IDs. */
val CITY_AREA_MAP: Map<String, Long> = mapOf(
    "Popayan"  to 1L,
    "Cali"     to 2L,
    "Medellin" to 3L,
    "Bogota"   to 4L
)

/** Returns the area ID for the given city name (case-insensitive, accent-insensitive). */
fun cityNameToAreaId(cityName: String): Long? {
    val normalized = cityName.normalizeCityToken()
    return CITY_AREA_MAP.entries.firstOrNull {
        val cityKey = it.key.normalizeCityToken()
        cityKey == normalized || cityKey.contains(normalized) || normalized.contains(cityKey)
    }?.value
}

private fun String.normalizeCityToken(): String {
    return Normalizer.normalize(trim(), Normalizer.Form.NFD)
        .replace("\\p{InCombiningDiacriticalMarks}+".toRegex(), "")
        .lowercase()
}

